import{_ as e,o as l,c as t,a2 as o}from"./chunks/framework.Bjylvv1V.js";const u=JSON.parse('{"title":"차량 등록/관리","description":"","frontmatter":{},"headers":[],"relativePath":"guide/scenarios/vehicle.md","filePath":"guide/scenarios/vehicle.md","lastUpdated":null}'),i={name:"guide/scenarios/vehicle.md"};function r(s,a,n,h,c,d){return l(),t("div",null,[...a[0]||(a[0]=[o(`<h1 id="차량-등록-관리" tabindex="-1">차량 등록/관리 <a class="header-anchor" href="#차량-등록-관리" aria-label="Permalink to &quot;차량 등록/관리&quot;">​</a></h1><blockquote><p><strong>소요 시간</strong>: 건당 약 5분 | <strong>난이도</strong>: ★★☆ | <strong>주기</strong>: 수시 (전출입 발생 시)</p></blockquote><p>입주 세대의 차량을 등록·관리하는 프로세스입니다.</p><h2 id="전체-흐름" tabindex="-1">전체 흐름 <a class="header-anchor" href="#전체-흐름" aria-label="Permalink to &quot;전체 흐름&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. 입주 차량 등록       (3분)  → 개별 입력 또는 엑셀 일괄 등록</span></span>
<span class="line"><span>2. 차량 현황 확인       (2분)  → 등록 차량 조회</span></span>
<span class="line"><span>3. 전출 시 차량 해제    (1분)  → 퇴거 세대 차량 삭제</span></span></code></pre></div><hr><h2 id="_1단계-입주-차량-등록-3분" tabindex="-1">1단계: 입주 차량 등록 (3분) <a class="header-anchor" href="#_1단계-입주-차량-등록-3분" aria-label="Permalink to &quot;1단계: 입주 차량 등록 (3분)&quot;">​</a></h2><blockquote><p><strong>메뉴 경로</strong>: 입주자 &gt; <a href="/occp/vehicle.html">차량관리</a> &gt; 차량일괄등록 (OCCP0130)</p></blockquote><p>입주 세대의 차량을 동/호수 기준으로 등록합니다.</p><h3 id="개별-등록-절차" tabindex="-1">개별 등록 절차 <a class="header-anchor" href="#개별-등록-절차" aria-label="Permalink to &quot;개별 등록 절차&quot;">​</a></h3><ol><li>차량일괄등록 화면 진입</li><li>동·호수 입력 후 <strong>조회</strong> 클릭</li><li>해당 세대의 차량 행에 <strong>차량번호</strong> 입력</li><li>차종, 색상, 차량 소유자 정보 입력 (해당 시)</li><li><strong>저장</strong> 클릭</li></ol><h3 id="엑셀-일괄-등록-절차" tabindex="-1">엑셀 일괄 등록 절차 <a class="header-anchor" href="#엑셀-일괄-등록-절차" aria-label="Permalink to &quot;엑셀 일괄 등록 절차&quot;">​</a></h3><p>신규 단지 또는 대량 등록이 필요한 경우:</p><ol><li>화면 상단 <strong>엑셀자료올리기</strong> 버튼 클릭</li><li>엑셀 템플릿 양식 다운로드</li><li>동, 호수, 차량번호 등 정보 입력</li><li>파일 형식: <strong>Excel 97-2003(.xls)</strong></li><li>파일 업로드 후 내용 확인</li><li><strong>저장</strong> 클릭</li></ol><h3 id="체크리스트" tabindex="-1">체크리스트 <a class="header-anchor" href="#체크리스트" aria-label="Permalink to &quot;체크리스트&quot;">​</a></h3><ul><li>[ ] 동·호수와 차량번호가 정확한가?</li><li>[ ] 세대당 등록 가능한 대수를 초과하지 않는가?</li><li>[ ] 전출 세대의 차량이 등록 해제되었는가?</li></ul><hr><h2 id="_2단계-전출-시-차량-해제" tabindex="-1">2단계: 전출 시 차량 해제 <a class="header-anchor" href="#_2단계-전출-시-차량-해제" aria-label="Permalink to &quot;2단계: 전출 시 차량 해제&quot;">​</a></h2><blockquote><p><strong>메뉴 경로</strong>: 입주자 &gt; <a href="/occp/vehicle.html">차량관리</a> &gt; 차량일괄등록 (OCCP0130)</p></blockquote><p>세대 전출 처리 후 해당 세대의 차량 등록을 해제합니다.</p><ol><li>차량일괄등록 화면에서 전출 세대 동·호수 조회</li><li>등록된 차량번호 삭제</li><li><strong>저장</strong> 클릭</li></ol><div class="warning custom-block"><p class="custom-block-title">전출 시 차량 등록 해제</p><p>세대 전출 처리 후 반드시 <strong>차량 등록 해제</strong> 여부를 확인하세요. 해제하지 않으면 퇴거 세대 차량이 계속 등록 상태로 남습니다.</p></div><hr><h2 id="자주-발생하는-문제" tabindex="-1">자주 발생하는 문제 <a class="header-anchor" href="#자주-발생하는-문제" aria-label="Permalink to &quot;자주 발생하는 문제&quot;">​</a></h2><h3 id="차량번호가-등록되지-않아요" tabindex="-1">차량번호가 등록되지 않아요 <a class="header-anchor" href="#차량번호가-등록되지-않아요" aria-label="Permalink to &quot;차량번호가 등록되지 않아요&quot;">​</a></h3><p><strong>원인</strong>: 차량번호 형식 오류 (특수문자, 공백 포함) 또는 동·호수 미입력 <strong>해결</strong>: 차량번호는 숫자와 한글만 입력합니다. 동·호수를 먼저 조회한 후 차량번호를 입력하세요.</p><h3 id="전출-세대-차량이-아직-등록되어-있어요" tabindex="-1">전출 세대 차량이 아직 등록되어 있어요 <a class="header-anchor" href="#전출-세대-차량이-아직-등록되어-있어요" aria-label="Permalink to &quot;전출 세대 차량이 아직 등록되어 있어요&quot;">​</a></h3><p><strong>원인</strong>: 전출 처리 시 차량 등록 해제 누락 <strong>해결</strong>: 차량일괄등록(OCCP0130)에서 해당 세대를 조회한 후 차량번호를 삭제하고 저장하세요.</p><hr><h2 id="관련-메뉴" tabindex="-1">관련 메뉴 <a class="header-anchor" href="#관련-메뉴" aria-label="Permalink to &quot;관련 메뉴&quot;">​</a></h2><ul><li><a href="/occp/vehicle.html">차량관리</a> - 차량 등록·조회</li><li><a href="/occp/move-in.html">입주처리</a> - 전입 시 차량 등록</li><li><a href="/occp/move-out.html">전출처리</a> - 전출 시 차량 해제</li><li><a href="/guide/scenarios/move-in-out.html">전출입 처리</a> - 전출입 전체 프로세스</li></ul>`,31)])])}const g=e(i,[["render",r]]);export{u as __pageData,g as default};
